<template>
  <div class="sales-statistics-container">
    <!-- 顶部指标卡片 -->
    <div class="overview-cards">
      <el-row :gutter="20">
        <el-col :span="6">
          <div class="indicator-card card-sales">
            <div class="card-icon">
              <i class="el-icon-money"></i>
            </div>
            <div class="card-body">
              <div class="card-label">总销售额</div>
              <div class="card-value">¥{{ formatNumber(overview.totalSales) }}</div>
              <div class="card-compare" :class="overview.salesGrowth >= 0 ? 'up' : 'down'">
                <i :class="overview.salesGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                较上期 {{ Math.abs(overview.salesGrowth) }}%
              </div>
            </div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="indicator-card card-orders">
            <div class="card-icon">
              <i class="el-icon-s-order"></i>
            </div>
            <div class="card-body">
              <div class="card-label">总订单数</div>
              <div class="card-value">{{ formatInteger(overview.totalOrders) }}</div>
              <div class="card-compare" :class="overview.ordersGrowth >= 0 ? 'up' : 'down'">
                <i :class="overview.ordersGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                较上期 {{ Math.abs(overview.ordersGrowth) }}%
              </div>
            </div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="indicator-card card-avg">
            <div class="card-icon">
              <i class="el-icon-s-marketing"></i>
            </div>
            <div class="card-body">
              <div class="card-label">客单价</div>
              <div class="card-value">¥{{ formatNumber(overview.averageOrderValue) }}</div>
              <div class="card-compare" :class="overview.aovGrowth >= 0 ? 'up' : 'down'">
                <i :class="overview.aovGrowth >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
                较上期 {{ Math.abs(overview.aovGrowth) }}%
              </div>
            </div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="indicator-card card-refund">
            <div class="card-icon">
              <i class="el-icon-refresh-left"></i>
            </div>
            <div class="card-body">
              <div class="card-label">退款金额</div>
              <div class="card-value">¥{{ formatNumber(overview.totalRefunds) }}</div>
              <div class="card-compare" :class="overview.refundsGrowth <= 0 ? 'up' : 'down'">
                <i :class="overview.refundsGrowth <= 0 ? 'el-icon-bottom' : 'el-icon-top'"></i>
                较上期 {{ Math.abs(overview.refundsGrowth) }}%
              </div>
            </div>
          </div>
        </el-col>
      </el-row>
    </div>

    <!-- 筛选区域 -->
    <el-card class="filter-card" shadow="never">
      <el-form :inline="true" :model="filterForm" size="small">
        <el-form-item label="日期范围">
          <el-date-picker
            v-model="filterForm.dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            value-format="yyyy-MM-dd"
            :picker-options="pickerOptions"
          />
        </el-form-item>
        <el-form-item label="时间粒度">
          <el-select v-model="filterForm.granularity" placeholder="请选择">
            <el-option label="按日" value="day" />
            <el-option label="按周" value="week" />
            <el-option label="按月" value="month" />
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" icon="el-icon-search" @click="handleSearch">
            查询
          </el-button>
          <el-button icon="el-icon-download" @click="handleExport">
            导出Excel
          </el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <!-- 销售趋势图 -->
    <el-card class="chart-card" shadow="never">
      <div slot="header" class="chart-header">
        <span class="chart-title">销售趋势</span>
      </div>
      <div class="chart-body">
        <div ref="trendChart" class="chart-canvas"></div>
      </div>
    </el-card>

    <!-- 分类销售额占比 + 热销排行 -->
    <el-row :gutter="20" class="bottom-row">
      <el-col :span="12">
        <el-card class="chart-card" shadow="never">
          <div slot="header" class="chart-header">
            <span class="chart-title">各分类销售额占比</span>
          </div>
          <div class="chart-body">
            <div ref="categoryChart" class="chart-canvas chart-canvas-bar"></div>
          </div>
        </el-card>
      </el-col>
      <el-col :span="12">
        <el-card class="chart-card" shadow="never">
          <div slot="header" class="chart-header">
            <span class="chart-title">热销商品排行</span>
          </div>
          <div class="chart-body ranking-body">
            <el-table :data="productRanking" stripe size="small" max-height="360">
              <el-table-column type="index" label="排名" width="55" align="center" />
              <el-table-column prop="name" label="商品名称" min-width="140" show-overflow-tooltip />
              <el-table-column prop="salesVolume" label="销量" width="100" align="center" />
              <el-table-column label="销售额" width="120" align="right">
                <template slot-scope="{ row }">
                  <span class="amount-cell">¥{{ formatNumber(row.salesAmount) }}</span>
                </template>
              </el-table-column>
            </el-table>
            <el-empty v-if="!loading && productRanking.length === 0" description="暂无数据" />
          </div>
        </el-card>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import * as echarts from 'echarts'
import statisticsApi from '@/api/statistics'

const TEA_COLOR = '#9c6e21'
const CHART_COLORS = ['#9c6e21', '#c9953b', '#e0b96a', '#f0d89a', '#d4a64a', '#b8862d']

export default {
  name: 'SalesStatistics',

  data() {
    const now = new Date()
    const lastMonth = new Date()
    lastMonth.setMonth(lastMonth.getMonth() - 1)

    return {
      filterForm: {
        dateRange: [this.fmtDate(lastMonth), this.fmtDate(now)],
        granularity: 'day'
      },
      pickerOptions: {
        shortcuts: [
          { text: '最近7天', onClick(p) { const e = new Date(); const s = new Date(); s.setDate(s.getDate() - 7); p.$emit('pick', [s, e]) } },
          { text: '最近30天', onClick(p) { const e = new Date(); const s = new Date(); s.setDate(s.getDate() - 30); p.$emit('pick', [s, e]) } },
          { text: '最近90天', onClick(p) { const e = new Date(); const s = new Date(); s.setDate(s.getDate() - 90); p.$emit('pick', [s, e]) } }
        ]
      },
      overview: {
        totalSales: 0,
        salesGrowth: 0,
        totalOrders: 0,
        ordersGrowth: 0,
        averageOrderValue: 0,
        aovGrowth: 0,
        totalRefunds: 0,
        refundsGrowth: 0
      },
      trendData: { dates: [], sales: [], orders: [] },
      categoryData: [],
      productRanking: [],
      loading: false,
      trendChart: null,
      categoryChart: null
    }
  },

  mounted() {
    this.fetchAll()
    window.addEventListener('resize', this.handleResize)
  },

  beforeDestroy() {
    window.removeEventListener('resize', this.handleResize)
    this.disposeCharts()
  },

  methods: {
    fmtDate(d) {
      const y = d.getFullYear()
      const m = String(d.getMonth() + 1).padStart(2, '0')
      const day = String(d.getDate()).padStart(2, '0')
      return `${y}-${m}-${day}`
    },

    formatNumber(val) {
      if (val == null) return '0.00'
      return Number(val).toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    },

    formatInteger(val) {
      if (val == null) return '0'
      return Number(val).toLocaleString('zh-CN')
    },

    handleSearch() {
      this.fetchAll()
    },

    async fetchAll() {
      this.loading = true
      const [s, e] = this.filterForm.dateRange || []
      const baseParams = { startDate: s, endDate: e, granularity: this.filterForm.granularity }

      try {
        const [salesRes, categoryRes, rankRes] = await Promise.all([
          statisticsApi.getSales(baseParams),
          statisticsApi.getCategorySales({ startDate: s, endDate: e }),
          statisticsApi.getProductRanking({ startDate: s, endDate: e, limit: 20 })
        ])

        // 概览 + 趋势
        if (salesRes && salesRes.code === 0 && salesRes.data) {
          const d = salesRes.data
          this.overview = {
            totalSales: d.totalSales || 0,
            salesGrowth: d.salesGrowth || 0,
            totalOrders: d.totalOrders || 0,
            ordersGrowth: d.ordersGrowth || 0,
            averageOrderValue: d.averageOrderValue || 0,
            aovGrowth: d.aovGrowth || 0,
            totalRefunds: d.totalRefunds || 0,
            refundsGrowth: d.refundsGrowth || 0
          }
          this.trendData = {
            dates: d.trendDates || [],
            sales: d.trendSales || [],
            orders: d.trendOrders || []
          }
          this.$nextTick(() => this.initTrendChart())
        }

        // 分类销售占比
        if (categoryRes && categoryRes.code === 0 && categoryRes.data) {
          this.categoryData = categoryRes.data
          this.$nextTick(() => this.initCategoryChart())
        }

        // 热销商品排行
        if (rankRes && rankRes.code === 0 && rankRes.data) {
          this.productRanking = (rankRes.data.list || rankRes.data || []).slice(0, 20)
        }
      } catch (err) {
        console.error('获取统计数据失败:', err)
        this.$message.error('获取统计数据失败，请稍后重试')
      } finally {
        this.loading = false
      }
    },

    // ============ 销售趋势图（双Y轴折线图）============
    initTrendChart() {
      this.disposeChart('trendChart')
      const dom = this.$refs.trendChart
      if (!dom) return

      this.trendChart = echarts.init(dom)
      this.trendChart.setOption({
        color: [TEA_COLOR, '#409EFF'],
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'cross', crossStyle: { color: '#999' } }
        },
        legend: {
          data: ['销售额', '订单数'],
          bottom: 0
        },
        grid: { left: '3%', right: '4%', bottom: '12%', top: '8%', containLabel: true },
        xAxis: {
          type: 'category',
          boundaryGap: false,
          data: this.trendData.dates,
          axisLine: { lineStyle: { color: '#dcdfe6' } },
          axisLabel: { color: '#909399' }
        },
        yAxis: [
          {
            type: 'value',
            name: '销售额 (元)',
            position: 'left',
            axisLabel: { formatter: '{value}', color: TEA_COLOR },
            splitLine: { lineStyle: { color: '#f2f2f2', type: 'dashed' } }
          },
          {
            type: 'value',
            name: '订单数',
            position: 'right',
            axisLabel: { color: '#409EFF' },
            splitLine: { show: false }
          }
        ],
        series: [
          {
            name: '销售额',
            type: 'line',
            yAxisIndex: 0,
            smooth: true,
            symbol: 'circle',
            symbolSize: 6,
            lineStyle: { width: 2.5 },
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(156,110,33,0.25)' },
                { offset: 1, color: 'rgba(156,110,33,0.02)' }
              ])
            },
            data: this.trendData.sales
          },
          {
            name: '订单数',
            type: 'line',
            yAxisIndex: 1,
            smooth: true,
            symbol: 'circle',
            symbolSize: 6,
            lineStyle: { width: 2.5 },
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(64,158,255,0.2)' },
                { offset: 1, color: 'rgba(64,158,255,0.02)' }
              ])
            },
            data: this.trendData.orders
          }
        ]
      })
    },

    // ============ 分类销售额柱状图 ============
    initCategoryChart() {
      this.disposeChart('categoryChart')
      const dom = this.$refs.categoryChart
      if (!dom) return

      const names = this.categoryData.map((it) => it.name || it.categoryName)
      const values = this.categoryData.map((it) => it.value || it.salesAmount || it.amount)

      this.categoryChart = echarts.init(dom)
      this.categoryChart.setOption({
        color: CHART_COLORS,
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'shadow' },
          formatter: (params) => {
            const p = params[0]
            return `${p.name}<br/>销售额: ¥${this.formatNumber(p.value)}`
          }
        },
        grid: { left: '3%', right: '8%', bottom: '8%', top: '8%', containLabel: true },
        xAxis: {
          type: 'category',
          data: names,
          axisLabel: { rotate: names.length > 6 ? 30 : 0, color: '#606266', fontSize: 11 },
          axisLine: { lineStyle: { color: '#dcdfe6' } }
        },
        yAxis: {
          type: 'value',
          name: '销售额 (元)',
          axisLabel: { formatter: '{value}', color: '#909399' },
          splitLine: { lineStyle: { color: '#f2f2f2', type: 'dashed' } }
        },
        series: [
          {
            name: '销售额',
            type: 'bar',
            barWidth: '45%',
            itemStyle: {
              borderRadius: [6, 6, 0, 0],
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: '#c9953b' },
                { offset: 1, color: '#7a5319' }
              ])
            },
            emphasis: {
              itemStyle: { color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: '#d4a64a' },
                { offset: 1, color: '#9c6e21' }
              ]) }
            },
            data: values
          }
        ]
      })
    },

    // ============ 导出 ============
    async handleExport() {
      try {
        const [s, e] = this.filterForm.dateRange || []
        const params = {
          startDate: s,
          endDate: e,
          granularity: this.filterForm.granularity
        }
        const res = await statisticsApi.getSales(params, { responseType: 'blob' })
        if (res instanceof Blob) {
          const url = window.URL.createObjectURL(res)
          const a = document.createElement('a')
          a.href = url
          a.download = `销售统计_${s}_${e}.xlsx`
          a.click()
          window.URL.revokeObjectURL(url)
          this.$message.success('导出成功')
        } else {
          this.$message.warning('导出失败，请检查接口配置')
        }
      } catch (err) {
        console.error('导出失败:', err)
        this.$message.warning('导出功能需要后台接口支持，请确认接口配置')
      }
    },

    // ============ 工具方法 ============
    disposeChart(key) {
      const chart = this[key]
      if (chart) {
        chart.dispose()
        this[key] = null
      }
    },

    disposeCharts() {
      this.disposeChart('trendChart')
      this.disposeChart('categoryChart')
    },

    handleResize() {
      this.trendChart && this.trendChart.resize()
      this.categoryChart && this.categoryChart.resize()
    }
  }
}
</script>

